const item = $input.first();
const filename = item.json.name || 'unknown.txt';
const ext = filename.split('.').pop().toLowerCase();
return [{ json: { filename, ext, fileId: item.json.id, ...item.json } }];

// Carry forward file metadata alongside extracted text
const text = $input.first().json.text || $input.first().json.data || '';
const fileMeta = $('Detect File Type').first().json;
return [{ json: { ...fileMeta, text, chatInput: text } }];

// AI Agent with Structured Output Parser → output is at $json.output (already parsed object)
const v = $input.first().json.output || {};
if (!v.flags) v.flags = [];

// Carry forward file metadata from earlier node
const fileMeta = $('Prepare Agent Input').first().json;

const dur = v.engagement_duration_months;
const sen = v.seniority_level;

// ─── TIER SELECTION LOGIC ────────────────────────────────────────────────────
// Maps seniority + duration → tier. When ambiguous, flag and default to IGNITE.
let tier;
if (sen === 'Advisory') {
  tier = 'AIIR_VISTA';
} else if (sen === 'C-Suite' && dur >= 10) {
  tier = 'ASCENT';
} else if (sen === 'C-Suite' && dur >= 6) {
  tier = 'ASCENT'; // C-Suite always ASCENT regardless of shorter duration
  v.flags.push('TIER_AMBIGUOUS_DURATION');
} else if (sen === 'Senior' && dur >= 6 && dur <= 9) {
  tier = 'IGNITE';
} else if (sen === 'Senior' && dur > 9) {
  tier = 'IGNITE';
  v.flags.push('TIER_AMBIGUOUS_DURATION');
} else if (sen === 'Mid-level' && dur >= 4 && dur <= 6) {
  tier = 'ROADMAP';
} else if (sen === 'Early Career' && dur >= 4 && dur <= 5) {
  tier = 'SPARK_II';
} else if (sen === 'Early Career' && dur >= 3 && dur < 4) {
  tier = 'SPARK_I';
} else if (sen === 'Early Career') {
  tier = 'SPARK_I';
  v.flags.push('TIER_AMBIGUOUS_DURATION');
} else if (sen === 'Mid-level') {
  tier = 'ROADMAP';
  v.flags.push('TIER_AMBIGUOUS_DURATION');
} else if (sen === 'Senior') {
  tier = 'IGNITE';
  v.flags.push('TIER_AMBIGUOUS_DURATION');
} else {
  tier = 'IGNITE'; // hard default
  v.flags.push('TIER_AMBIGUOUS');
}

// If duration is missing, flag it
if (!dur) v.flags.push('DURATION_MISSING');

// ─── BILL RATE TABLE ─────────────────────────────────────────────────────────
// Rates are per hour. Market type + seniority level → bill rate.
// Source: AIIR rate card (as per project spec)
const rateTable = {
  'Mature': {
    'C-Suite':     600,
    'Senior':      350,
    'Mid-level':   250,
    'Early Career':250,
    'Advisory':    350
  },
  'Emerging': {
    'C-Suite':     500,
    'Senior':      300,
    'Mid-level':   200,
    'Early Career':200,
    'Advisory':    300
  }
};
const market = v.market_type || 'Mature';
const billRate = rateTable[market]?.[sen] || 350;

// ─── COACH NAME RULE ─────────────────────────────────────────────────────────
// Only use a named coach if chemistry call is explicitly confirmed as complete.
// Otherwise always use the generic placeholder.
const coachName = (v.chemistry_call_complete === true && v.coach_name)
  ? v.coach_name
  : 'a Senior Level AIIR Consultant';

// ─── DEFAULTS ────────────────────────────────────────────────────────────────
if (!v.num_participants || v.num_participants < 1) v.num_participants = 1;
if (!v.flags.includes('NO_CLIENT_EMAIL') && !v.client_email) {
  v.flags.push('NO_CLIENT_EMAIL');
}

return [{ json: {
  ...fileMeta,    // filename, fileId, etc.
  ...v,           // all GPT-extracted fields
  tier,
  billRate,
  coachName,
  margin: 0.65    // ALWAYS 0.65 — never read from file
} }];

const v = $input.first().json;
const tier = v.tier;
const hasBudget = v.budget_signal_detected === true;
const budgetTarget = v.budget_target_amount;

// ─── DEFAULT SESSION HOURS BY TIER ───────────────────────────────────────────
// These are the STARTING values before any reductions.
// B-cells = coaching hours per session
// E37_CZ = CZ (coaching platform) fee in months
// interviewCount = number of 360° interviews (used for SOW text)
const tierDefaults = {
  IGNITE: {
    B37: 0.5,   // Initial Coaching Session (fixed, never reduced)
    B38: 1.0,   // Stakeholder 1: ASM (Assimilation)
    B39: 2.0,   // Dev History Interview
    B40: 6.0,   // Interview-Based 360° (8 interviews × 45min ÷ 60 = 6.0)
    B41: 2.0,   // Assessment Feedback
    B42: 1.0,   // Dev Planning Session
    B43: 1.0,   // Stakeholder 2: SDP (Structured Development Planning)
    B44: 8.0,   // Implementation Sessions (8 × 1hr)
    B45: 1.0,   // Stakeholder 3: Midpoint
    B46: 1.0,   // Stakeholder 4: Wrap-Up
    E37_CZ: 9,  // CZ months — dynamically set from duration (range 7–9)
    interviewCount: 8
  },
  ROADMAP: {
    B37: 0.5, B38: 1.0, B39: 2.0,
    B40: 3.75, // 5 interviews × 45min ÷ 60
    B41: 2.0, B42: 1.0, B43: 1.0,
    B44: 5.0, B45: 1.0, B46: 1.0,
    E37_CZ: 6, interviewCount: 5
  },
  ASCENT: {
    B37: 0.5, B38: 1.0, B39: 2.0,
    B40: 9.0, // 12 interviews × 45min ÷ 60
    B41: 2.0, B42: 1.0, B43: 1.0,
    B44: 12.0, B45: 1.0, B46: 1.0,
    E37_CZ: 12, interviewCount: 12
  },
  SPARK_I: {
    B37: 0.5, B38: 1.0,
    B39: 0,   // ⚠️ SPARK I: NO Dev History Interview — uses $60 survey instead
    B40: 3.75, B41: 2.0, B42: 1.0,
    B43: 1.0, B44: 4.0, B45: 1.0, B46: 1.0,
    E37_CZ: 4, interviewCount: 5
  },
  SPARK_II: {
    B37: 0.5, B38: 1.0, B39: 2.0,
    B40: 3.75, B41: 2.0, B42: 1.0,
    B43: 1.0, B44: 5.0, B45: 1.0, B46: 1.0,
    E37_CZ: 5, interviewCount: 5
  },
  AIIR_VISTA: {
    B37: 0.5, B38: 1.0, B39: 2.0,
    B40: 6.0, B41: 2.0, B42: 1.0,
    B43: 1.0, B44: 10.0, B45: 1.0, B46: 1.0,
    E37_CZ: 12, interviewCount: 8
  }
};

let hours = { ...(tierDefaults[tier] || tierDefaults.IGNITE) };
let interviewCount = hours.interviewCount;
delete hours.interviewCount;

const reductions = [];

// ─── CZ FEE MONTHS — SET FROM ENGAGEMENT DURATION ────────────────────────────
const dur = v.engagement_duration_months || 9;
if (tier === 'IGNITE') {
  // IGNITE: CZ months = engagement duration, clamped between 7 and 9
  hours.E37_CZ = Math.min(9, Math.max(7, Math.round(dur)));
} else if (tier === 'ASCENT') {
  // ASCENT: CZ months = engagement duration, clamped between 10 and 12
  hours.E37_CZ = Math.min(12, Math.max(10, Math.round(dur)));
}
// Other tiers: E37_CZ is fixed (already set in tierDefaults)

// ─── 360° SUB-DECISION LOGIC ─────────────────────────────────────────────────
// This runs BEFORE budget levers so we know if 360 is in/out before pricing.
let interview360Action = 'KEEP'; // KEEP | REDUCE | ELIMINATE

if (v.existing_360_status === 'recent' || (v.existing_360_phrases && v.existing_360_phrases.length > 0)) {
  // Recent 360 data exists → eliminate the 360 interview component entirely
  interview360Action = 'ELIMINATE';
  hours.B40 = 0;
  interviewCount = 0;
  reductions.push({ field: '360', action: 'ELIMINATED', reason: 'Recent 360 data available in transcript' });
  if (!v.flags.includes('360_ELIMINATE_REVIEW')) {
    v.flags.push('360_ELIMINATE_REVIEW');
  }
} else if (v.self_awareness_signals && v.self_awareness_signals.length > 0) {
  // Coachee is seeking self-awareness / feedback → KEEP 360 at full value
  interview360Action = 'KEEP';
} else if (hasBudget && interviewCount > 5) {
  // Budget pressure + no strong self-awareness signal → REDUCE to minimum
  interview360Action = 'REDUCE';
  interviewCount = 5; // HARD FLOOR: never fewer than 5 interviews
  hours.B40 = parseFloat(((45 * interviewCount) / 60).toFixed(2)); // 3.75
  reductions.push({ field: '360', action: 'REDUCED', to: interviewCount, reason: 'Budget signal detected, reduced to minimum 5 interviews' });
}

// ─── 6-LEVER BUDGET REDUCTION HIERARCHY ─────────────────────────────────────
// Applied ONLY if a budget signal was detected.
// Levers applied in order of priority — earlier levers affect scope less.
// All levers applied simultaneously here (not sequential stops) to give reviewer full picture.

if (hasBudget) {

  // LEVER 1: Stakeholder sessions 1hr → 0.75hr
  // (Stakeholder 1 ASM, Stakeholder 2 SDP, Midpoint, Wrap-Up)
  for (const cell of ['B38', 'B43', 'B45', 'B46']) {
    if (hours[cell] > 0.75) {
      reductions.push({ cell, from: hours[cell], to: 0.75, lever: 1, description: 'Stakeholder session shortened from 1hr to 45min' });
      hours[cell] = 0.75;
    }
  }

  // LEVER 2: Dev History Interview 2hr → 1.5hr
  // (Skip for SPARK_I — it has no Dev History Interview at all)
  if (tier !== 'SPARK_I' && hours.B39 > 1.5) {
    reductions.push({ cell: 'B39', from: hours.B39, to: 1.5, lever: 2, description: 'Dev History shortened from 2hr to 90min' });
    hours.B39 = 1.5;
  }

  // LEVER 3: 360° already handled above (reduction or elimination)

  // LEVER 4: Implementation Sessions reduced by 1 session
  if (hours.B44 > 7) {
    reductions.push({ cell: 'B44', from: hours.B44, to: hours.B44 - 1, lever: 4, description: 'One implementation session removed' });
    hours.B44 = hours.B44 - 1;
  }

  // LEVER 5: Dev Planning Session removed entirely
  // (Only if budget target is set and low — strongest indicator of budget pressure)
  if (budgetTarget && budgetTarget < 35000 && hours.B42 > 0) {
    reductions.push({ cell: 'B42', from: hours.B42, to: 0, lever: 5, description: 'Dev Planning Session removed — strong budget constraint' });
    hours.B42 = 0;
  }

  // LEVER 6: Assessment Feedback 2hr → 1.5hr
  // Note: 2hrs is default (delete SOW sentence), 1.5hrs triggers SOW sentence update
  if (hours.B41 > 1.5) {
    reductions.push({ cell: 'B41', from: hours.B41, to: 1.5, lever: 6, description: 'Assessment Feedback shortened from 2hr to 90min (SOW sentence updated)' });
    hours.B41 = 1.5;
  }
}

return [{ json: { ...v, hours, reductions, interview360Action, interviewCount } }];

const v = $input.first().json;

// ─── PAYMENT STRUCTURE ───────────────────────────────────────────────────────
// DEFAULT is 100% upfront — this overrides any 50/50 default in the SOW template.
// Only switch to 50/50 if the transcript explicitly signals it.
let paymentStructure = '100% invoiced upon program kickoff';
let netDays = 30; // Default: Net 30

if (v.payment_structure_signal === '50_50') {
  paymentStructure = '50% invoiced upon program kickoff. 50% invoiced three months following program kickoff.';
} else if (v.payment_structure_signal === 'milestone') {
  // Milestone payment is non-standard — keep 100% upfront but flag for review
  paymentStructure = '100% invoiced upon program kickoff';
  if (!v.flags.includes('PAYMENT_MILESTONE_SIGNAL')) {
    v.flags.push('PAYMENT_MILESTONE_SIGNAL');
  }
}

// Override net days only if explicitly detected
if (v.net_days_signal === 45) netDays = 45;
else if (v.net_days_signal === 60) netDays = 60;
// else stays at 30

// ─── CZ RATE PER TIER ────────────────────────────────────────────────────────
// ASCENT and AIIR_VISTA use $50/mo. All others use $75/mo.
const czRate = (v.tier === 'ASCENT' || v.tier === 'AIIR_VISTA') ? 50 : 75;

// ─── FIXED ASSESSMENT FEES PER TIER ─────────────────────────────────────────
// These are non-CZ assessment costs (psychometric tools, LD12, Hogan, surveys).
// Source: AIIR pricing Excel — verified per tier.
//
// IGNITE:   LD12 $150 + Hogan $300 = $450 base (always, even if 360 eliminated)
// ROADMAP:  LD12 360° $350 (only if 360 included)
// ASCENT:   LD12 360° $350 (only if 360 included)
// SPARK_I:  LD12 $150 + Hogan $300 + Dev History Survey $60 = $510 base
//           + Survey-based 360° $350 (if 360 included)
// SPARK_II: Survey 360° $350 (only if 360 included)
// AIIR_VISTA: LD12 360° $350 (only if 360 included)
const has360 = v.interview360Action !== 'ELIMINATE';
const assessmentFeeMap = {
  IGNITE:    { base: 450, fee360: 0   },  // 360 has no separate fee in IGNITE
  ROADMAP:   { base: 0,   fee360: 350 },
  ASCENT:    { base: 0,   fee360: 350 },
  SPARK_I:   { base: 510, fee360: 350 },
  SPARK_II:  { base: 0,   fee360: 350 },
  AIIR_VISTA:{ base: 0,   fee360: 350 },
};
const feeEntry = assessmentFeeMap[v.tier] || assessmentFeeMap.IGNITE;
const fixedAssessmentFees = feeEntry.base + (has360 ? feeEntry.fee360 : 0);

return [{ json: { ...v, paymentStructure, netDays, czRate, fixedAssessmentFees } }];

const v = $input.first().json;
const timestamp = Date.now();
const random = Math.random().toString(36).substr(2, 6).toUpperCase();
const engagementId = `AIIR-${timestamp}-${random}`;
const createdAt = new Date().toISOString();
return [{ json: { ...v, engagementId, createdAt } }];

const sheetsResponse = $input.first().json;
const prevData = $('Generate Engagement ID').first().json;

// H48 = price per participant, H49 = (intermediate row), H50 = total engagement price
const values = sheetsResponse.values || [];
const raw48 = (values[0]?.[0] || '0').toString().replace(/[,$]/g, '');
const raw50 = (values[2]?.[0] || values[0]?.[0] || '0').toString().replace(/[,$]/g, '');

const pricePerParticipant = parseFloat(raw48) || 0;
const totalEngagementPrice = parseFloat(raw50) || pricePerParticipant;

return [{ json: { ...prevData, pricePerParticipant, totalEngagementPrice } }];

parameters.text:
=Generate a pricing rationale document for the following AIIR Consulting engagement.

## ENGAGEMENT DATA
- Engagement ID: {{ $json.engagementId }}
- Client Company: {{ $json.client_company }}
- Coachee: {{ $json.coachee_name }} ({{ $json.seniority_title }})
- Tier Selected: {{ $json.tier }}
- Seniority Level: {{ $json.seniority_level }}
- Market Type: {{ $json.market_type }} ({{ $json.market_country }})
- Engagement Duration: {{ $json.engagement_duration_months }} months
- Bill Rate: ${{ $json.billRate }}/hr
- Margin: 0.65 (fixed)
- Participants: {{ $json.num_participants }}
- Price Per Participant: ${{ $json.pricePerParticipant }}
- TOTAL ENGAGEMENT PRICE: ${{ $json.totalEngagementPrice }}
- CZ Fee Months: {{ $json.hours.E37_CZ }}
- Payment Structure: {{ $json.paymentStructure }}
- Net Days: {{ $json.netDays }}
- 360° Decision: {{ $json.interview360Action }} ({{ $json.interviewCount }} interviews)

## REDUCTIONS APPLIED
{{ JSON.stringify($json.reductions, null, 2) }}

## HOURS BREAKDOWN
{{ JSON.stringify($json.hours, null, 2) }}

## FLAGS FOR HUMAN REVIEW
{{ JSON.stringify($json.flags) }}

## BUDGET SIGNALS DETECTED
{{ JSON.stringify($json.budget_signal_phrases) }}

Write the rationale document now.

parameters.jsCode:
const pricingData = $('Parse Price From Response').first().json;
const rationaleAgent = $('AI Agent: Generate Rationale').first().json;
const rationaleDoc = $('Save Rationale to Google Drive').first().json;

// AI Agent output is in $json.output
const rationaleText = rationaleAgent.output || 'Rationale not available — check AI Agent node execution.';

const rationaleDocId = rationaleDoc.id || '';
const rationaleDocUrl = rationaleDocId
  ? `https://docs.google.com/document/d/${rationaleDocId}/edit`
  : 'Not available';

// Build sheet URL — replace placeholder with actual sheet ID
const sheetId = $vars?.AIIR_PRICING_SHEET_ID || 'AIIR_PRICING_SHEET_ID_PLACEHOLDER';
const sheetUrl = `https://docs.google.com/spreadsheets/d/${sheetId}/edit`;

return [{ json: {
  ...pricingData,
  rationaleText,
  rationaleDocId,
  rationaleDocUrl,
  sheetUrl
} }];
